SELECT
, r.id AS "role.id", r.name AS "role.name", r.enname AS "role.enname"
FROM sys_user a
LEFT JOIN sys_user_role ur ON ur.user_id = a.id LEFT JOIN sys_role r ON r.id = ur.role_id
WHERE a.del_flag = #{DEL_FLAG_NORMAL}
AND ur.role_id = #{role.id}
AND (c.id = #{company.id} OR c.parent_ids LIKE CONCAT('%,', #{company.id}, ',%'))
AND (o.id = #{office.id} OR o.parent_ids LIKE CONCAT('%,', #{office.id}, ',%'))
AND a.post_id = #{post.id}
AND a.id != '1'
AND a.login_name like CONCAT('%', #{loginName}, '%')
AND a.name like CONCAT('%', #{name}, '%')
${dataScope}
AND ( a.login_date IS NULL OR a.login_date < DATE_SUB(NOW(), INTERVAL #{inactiveDays} DAY) )
ORDER BY ${page.orderBy}
ORDER BY c.code, o.code, a.name

SELECT

FROM sys_user a


WHERE a.del_flag = #{DEL_FLAG_NORMAL}

	AND c.id = #{company.id}


	AND o.id = #{office.id}


	AND (o.id = ''  or o.id is null)



	AND a.login_name like CONCAT('%', #{loginName}, '%')


	AND a.name like CONCAT('%', #{name}, '%')


${dataScope}

ORDER BY  a.name

SELECT
	a.id, a.name, a.login_name
FROM sys_user a
WHERE a.del_flag = #{DEL_FLAG_NORMAL}
  AND a.office_id = #{office.id}
ORDER BY a.name

