	password = #{password}
WHERE id = #{id}

UPDATE sys_user SET
					login_ip = #{loginIp},
					login_Date = #{loginDate}
WHERE id = #{id}

UPDATE sys_user SET
	del_flag = #{DEL_FLAG_DELETE}
WHERE id = #{id}

UPDATE sys_user
SET two_factor_code = #{twoFactorCode},
	two_factor_time = #{twoFactorTime}
WHERE id = #{id}
